import fs from "node:fs";
import path from "node:path";

const files = {"app/layout.tsx":"","app/page.tsx":"","app/styles.css":""};
for (const [relativePath, encoded] of Object.entries(files)) {
  const target = path.join(process.cwd(), relativePath);
  const shouldRestore = !fs.existsSync(target) || fs.statSync(target).size === 0;
  if (shouldRestore) {
    fs.mkdirSync(path.dirname(target), { recursive: true });
    fs.writeFileSync(target, Buffer.from(encoded, "base64"));
    console.log(`[TradeSea] Restored ${relativePath}`);
  } else {
    console.log(`[TradeSea] Verified ${relativePath}`);
  }
}

if (!fs.existsSync(path.join(process.cwd(), "app", "page.tsx"))) {
  throw new Error("TradeSea build bootstrap could not create app/page.tsx");
}
